  /**
   * "/memoria [length]" — reveals a deterministic digit sequence (seeded,
   * never stored in plaintext) as number emoji, then waits for the player to
   * reply in the same chat within MEMORY_ANSWER_WINDOW_SECONDS. Starting a
   * new game while one is pending replaces it (single-attempt design).
   */
  private async handleMemoryCommand(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (update.command?.name !== "memoria") {
      return null;
    }
    if (!update.user.userId) {
      return { text: "No puedo identificarte." };
    }
    if (!context.chatId) {
      return { text: "Este juego se juega dentro de un chat." };
    }

    const length = parseMemoryLength(update.command.args);
    const seed = randomInt(0, 2 ** 31);
    const sequence = generateMemorySequence(
      seed,
      length,
      MEMORY_SEQUENCE_MAX_DIGIT,
    );

    const session = await this.memorySequenceRepository.start({
      tenantId: context.tenantId,
      chatId: context.chatId,
      telegramUserId: update.user.userId,
      seed,
      length,
    });

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "game.memory.started",
      resourceType: "memory_sequence_session",
      resourceId: session.id,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { length },
    });

    const emojis = sequence
      .map((digit) => MEMORY_DIGIT_EMOJI[digit] ?? "❔")
      .join(" ");

    return {
      text:
        `🧠 Memoriza esta secuencia:\n\n${emojis}\n\n` +
        `Responde en este chat con los ${length} números en el mismo orden ` +
        `(ej: "3 7 1 0"), en menos de ${MEMORY_ANSWER_WINDOW_SECONDS} segundos.`,
    };
  }

  /**
   * Verifies a plain-text reply against the player's active session. Only
   * ever "steals" a message from normal chat when (a) that user has an open
   * session in this chat AND (b) the text contains at least one digit — so
   * unrelated conversation passes through untouched. Right or wrong, this
   * attempt always closes the session (single try per /memoria).
   */
  private async handleMemoryAnswer(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<BotReply | null> {
    if (!update.isTextMessage || update.command || !update.messageText) {
      return null;
    }
    if (!update.user.userId || !context.chatId) {
      return null;
    }

    const session = await this.memorySequenceRepository.getActive(
      context.chatId,
      update.user.userId,
    );
    if (!session) {
      return null;
    }

    const given = parseMemoryAnswerDigits(update.messageText);
    if (!given) {
      return null;
    }

    const elapsedMs = Date.now() - session.startedAt.getTime();
    if (elapsedMs > MEMORY_ANSWER_WINDOW_SECONDS * 1000) {
      await this.memorySequenceRepository.clear(
        context.chatId,
        update.user.userId,
      );
      return {
        text: "⏱️ Se acabó el tiempo. Usa /memoria para intentarlo de nuevo.",
      };
    }

    const expected = generateMemorySequence(
      session.seed,
      session.length,
      MEMORY_SEQUENCE_MAX_DIGIT,
    );
    const result = checkMemoryAnswer(expected, given);

    await this.memorySequenceRepository.clear(
      context.chatId,
      update.user.userId,
    );

    if (!result.correct) {
      return {
        text: `❌ No era esa. Acertaste ${result.matched}/${session.length}. Usa /memoria para otro intento.`,
      };
    }

    await this.gameRepository.addScore(
      context.tenantId,
      context.chatId,
      update.user.userId,
      session.length,
    );

    await this.repository.recordAudit({
      tenantId: context.tenantId,
      actorType: "user",
      action: "game.memory.won",
      resourceType: "memory_sequence_session",
      resourceId: session.id,
      ...(context.userId ? { actorId: context.userId } : {}),
      payload: { length: session.length },
    });

    return {
      text: `🏆 ¡Correcto! +${session.length} puntos para ${update.user.username ?? update.user.userId.toString()}.`,
    };
  }
